const button = document.querySelector('button');
button.addEventListener('click', function() {
    alert('Saved!');
});

JButton button = new JButton("Save");
button.addActionListener(e -> {
    JOptionPane.showMessageDialog(null, "Saved!");
});
frame.add(button);

-- button interaction captured as stored procedure
CREATE PROCEDURE OnButtonClick AS
BEGIN
    INSERT INTO logs (action, timestamp) VALUES ('Saved', GETDATE());
END;
EXEC OnButtonClick;
